baseline.response_text:
{
  "id": "US-001",
  "role": "Link Sharer",
  "action": "Submit a long URL to generate a unique 6-char slug via POST endpoint",
  "outcome": "System stores encrypted original URL and assigns a unique VOC-SHORT-URL slug for immediate use",
  "priority": "critical",
  "traces_to": [
    "UJ-SUBMIT-NEW-LINK",
    "ENT-LINK",
    "COMP-PII-SANCTION"
  ],
  "acceptance_criteria": [
    {
      "id": "AC-001",
      "description": "Short URL generation succeeds for valid input",
      "measurable_condition": "POST /shortener with a valid URL payload returns HTTP 201 and includes a VOC-SHORT-URL field with a 6-character alphanumeric slug, with redirect resolution to the target URL occurring within VV-REDIRECT-LATENCY threshold"
    },
    {
      "id": "AC-002",
      "description": "Original URL is encrypted at rest",
      "measurable_condition": "Stored mapping of VOC-ORIGINAL-URL to VOC-SHORT-URL contains ciphertext values in primary storage, with no plaintext URL found in storage logs or VV-SECURITY-ENCRYPTION verification"
    },
    {
      "id": "AC-003",
      "description": "Invalid or missing input is rejected",
      "measurable_condition": "POST /shortener with missing, empty, or malformed URL field returns HTTP 400 with error code INVALID_URL and no record is persisted"
    },
    {
      "id": "AC-004",
      "description": "Generated slug is unique and persistent",
      "measurable_condition": "POST /shortener generates a unique slug for each request, and no collision occurs where two different VOC-ORIGINAL-URLs map to the same VOC-SHORT-URL slug"
    },
    {
      "id": "AC-005",
      "description": "Stored URL supports compliance-driven deletion",
      "measurable_condition": "DELETE /shortener/{slug} using the created VOC-SHORT-URL successfully removes the mapping from storage, confirming COMP-PII-SANCTION deletion obligation support"
    }
  ]
}
